arguments.new_str:
using System.IO.Compression;
using System.Text;
class ZipCreator
{
    static ZipCreator()
    {
        Encoding.RegisterProvider(CodePagesEncodingProvider.Instance);
    }

    void CreateArchive()
    {
        // .NET 9: ZipArchiveEntry now respects the UTF-8 flag, which breaks
        // the legacy Java consumer that reads filenames as Shift-JIS.
        // Explicitly specify Shift-JIS encoding so entry names are written
        // in the encoding the consumer expects.
        var shiftJis = Encoding.GetEncoding("shift_jis");
        using var archive = ZipFile.Open("data.zip", ZipArchiveMode.Create, shiftJis);
        archive.CreateEntry("レポート/月次.csv");  // Japanese path
        archive.CreateEntry("données/résumé.txt"); // French accented
    }
}

